1	/**
2	 * Layerinfinite — lib/scoring.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * 6-Factor Composite Scoring Engine
5	 * ══════════════════════════════════════════════════════════════
6	 *
7	 * FORMULA:
8	 *   composite_score = (
9	 *     w_success  * weighted_success_rate  +
10	 *     w_conf     * confidence             +
11	 *     w_trend    * trend_factor           +
12	 *     w_salience * salience_factor        +
13	 *     w_recency  * recency_factor         +
14	 *     w_latency  * latency_factor
15	 *   )
16	 *
17	 * Weights sum to 1.0. All inputs are normalised to [0, 1].
18	 *
19	 * Salience = importance weight of this action (from database).
20	 * Cold-start (confidence < MIN_CONFIDENCE): returns institutional priors.
21	 *
22	 * IN-MEMORY CACHE (5 min TTL):
23	 *   One entry per (action_id, context_id, customer_id).
24	 *   Refreshed on scoring-engine cron or on-demand.
25	 *   Falls back to DB query on cache miss.
26	 */
27	
28	import { supabase, ActionScore } from './supabase.js';
29	
30	// ── Weights ──────────────────────────────────────────────────
31	const W_SUCCESS = 0.40;  // primary driver
32	const W_CONF = 0.20;  // uncertainty penalty
33	const W_TREND = 0.20;  // directional momentum
34	const W_SALIENCE = 0.10;  // action importance
35	const W_RECENCY = 0.05;  // freshness bonus
36	const W_LATENCY = 0.05;  // response-time quality signal
37	
38	// Bayesian (Laplace) smoothing priors for composite score calculation.
39	// Used in computeCompositeScore(): (successes + α) / (total + α + β).
40	// NOTE: These are NOT used in updateAgentTrust() (outcome-orchestrator.ts),
41	// which uses exponential smoothing independently.
42	export const PRIOR_ALPHA = 1.0;  // Laplace prior successes (neutral = 1)
43	export const PRIOR_BETA = 1.0;  // Laplace prior failures  (neutral = 1)
44	
45	// ── Thresholds ───────────────────────────────────────────────
46	const MIN_CONFIDENCE = 0.15;  // below this → cold-start fallback (was 0.30; lowered so 2+ outcomes can differentiate)
47	const ESCALATION_SCORE = 0.20;  // below this → escalate_human
48	const CACHE_TTL_MS = 5 * 60 * 1000;  // 5 minutes
49	// LRU eviction: 1000 entries × ~2KB avg = ~2MB max resident cache size.
50	// V8 Map preserves insertion order; oldest key = first key in iterator.
51	// At 1000 entries, single-deletion eviction keeps memory bounded without
52	// a full LRU linked list implementation.
53	const MAX_CACHE_ENTRIES = 1000;
54	const IPS_DECISION_CHUNK_SIZE = 50;
55	const CLUSTER_PRIOR_MAX_BLEND = 0.15;
56	const CLUSTER_PRIOR_LOW_SAMPLE_THRESHOLD = 10;
57	const CLUSTER_PRIOR_STRONG_SIGNAL_MIN_SAMPLES = 50;
58	
59	function withTimeout<T>(promise: Promise<T>, ms: number): Promise<T | null> {
60	    return Promise.race([
61	        promise,
62	        new Promise<null>((resolve) => setTimeout(() => resolve(null), ms)),
63	    ]) as Promise<T | null>;
64	}
65	
66	// ── In-Memory Score Cache ─────────────────────────────────────
67	interface CacheEntry {
68	    scores: ScoredAction[];
69	    expires_at: number;
70	}
71	
72	const scoreCache = new Map<string, CacheEntry>();
73	
74	// Evict expired entries every 5 minutes
75	const CLEANUP_INTERVAL_MS = 5 * 60_000;
76	setInterval(() => {
77	    const now = Date.now();
78	    let evicted = 0;
79	    for (const [key, entry] of scoreCache.entries()) {
80	        if (entry.expires_at < now) {
81	            scoreCache.delete(key);
82	            evicted++;
83	        }
84	    }
85	    if (evicted > 0) {
86	        console.info(`[cache-cleanup] Evicted ${evicted} expired entries from scoreCache`);
87	    }
88	}, CLEANUP_INTERVAL_MS).unref();
89	
90	setInterval(() => {
91	    if (scoreCache.size > 0 && process.env['NODE_ENV'] !== 'production') {
92	        console.debug(`[cache-size] scoreCache: ${scoreCache.size} entries`);
93	    }
94	}, 15 * 60_000).unref();
95	
96	function cacheKey(customerId: string, contextId: string): string {
97	    return `${customerId}:${contextId}`;
98	}
99	
100	/**
101	 * Call this after any successful outcome write for (customerId, contextId).
102	 * Ensures the next getScores() call fetches fresh data from mv_action_scores
103	 * instead of serving a cached cold-start fallback.
104	 */
105	export function invalidateCache(customerId?: string, contextId?: string): void {
106	    if (customerId && contextId) {
107	        scoreCache.delete(cacheKey(customerId, contextId));
108	    } else {
109	        scoreCache.clear();
110	    }
111	}
112	
113	/**
114	 * Returns the cached composite score for a specific action in a context.
115	 * Used by log-outcome.ts for salience sampling:
116	 *   if (score > 0.9 && success) → salience = 0.1 (sampled down)
117	 * Returns null on cache miss (caller defaults to salience=1.0).
118	 */
119	export function getCachedScore(
120	    actionId: string,
121	    contextId: string,
122	    customerId: string
123	): number | null {
124	    // Scan the cache for this customer+context
125	    const key = cacheKey(customerId, contextId);
126	    const cached = scoreCache.get(key);
127	    if (!cached || cached.expires_at <= Date.now()) return null;
128	
129	    const match = cached.scores.find(s => s.action_id === actionId);
130	    return match ? match.composite_score : null;
131	}
132	
133	// ── Scoring types ─────────────────────────────────────────────
134	export type TrendLabel = 'stable' | 'improving' | 'degrading' | 'critical';
135	
136	export function trendLabel(trendDelta: number | null): TrendLabel {
137	    if (trendDelta === null) return 'stable';
138	    if (trendDelta <= -0.15) return 'critical';
139	    if (trendDelta < -0.05) return 'degrading';
140	    if (trendDelta > 0.05) return 'improving';
141	    return 'stable';
142	}
143	
144	export interface ScoredAction {
145	    action_id: string;
146	    action_name: string;
147	    action_category: string;
148	    composite_score: number;
149	    confidence: number;
150	    trend_delta: number | null;
151	    trend: TrendLabel;
152	    total_attempts: number;
153	    is_cold_start: boolean;
154	    is_low_sample: boolean;
155	    recommendation: 'recommend' | 'neutral' | 'avoid' | 'escalate';
156	}
157	
158	export interface ScoringResult {
159	    ranked_actions: ScoredAction[];
160	    top_action: ScoredAction;
161	    should_escalate: boolean;
162	    cold_start: boolean;
163	    context_id: string;
164	    customer_id: string;
165	    view_refreshed_at: string | null;
166	    served_from_cache: boolean;
167	}
168	
169	interface IPSBatchRow {
170	    unchosen_action_id: string | null;
171	    counterfactual_est: number | null;
172	    ips_weight: number | null;
173	    created_at: string | null;
174	}
175	
176	interface ClusterPrior {
177	    successRate: number;
178	    totalAttempts: number;
179	}
180	
181	function percentile(sortedValues: number[], q: number): number | null {
182	    if (sortedValues.length === 0) return null;
183	    if (sortedValues.length === 1) return sortedValues[0] ?? null;
184	
185	    const clampedQ = Math.max(0, Math.min(1, q));
186	    const idx = (sortedValues.length - 1) * clampedQ;
187	    const lo = Math.floor(idx);
188	    const hi = Math.ceil(idx);
189	    if (lo === hi) return sortedValues[lo] ?? null;
190	
191	    const loVal = sortedValues[lo] ?? 0;
192	    const hiVal = sortedValues[hi] ?? loVal;
193	    const frac = idx - lo;
194	    return loVal + (hiVal - loVal) * frac;
195	}
196	
197	function computeContextLatencyBaselineP75(rows: ActionScore[]): number | null {
198	    const latencies = rows
199	        .map((row) => row.avg_response_ms)
200	        .filter((v): v is number => typeof v === 'number' && Number.isFinite(v) && v > 0)
201	        .sort((a, b) => a - b);
202	
203	    return percentile(latencies, 0.75);
204	}
205	
206	function computeLatencyFactor(avgResponseMs: number | null | undefined, p75ResponseMs: number | null): number {
207	    if (typeof avgResponseMs !== 'number' || !Number.isFinite(avgResponseMs) || avgResponseMs <= 0) {
208	        return 0.5;
209	    }
210	    if (typeof p75ResponseMs !== 'number' || !Number.isFinite(p75ResponseMs) || p75ResponseMs <= 0) {
211	        return 0.5;
212	    }
213	
214	    // ratio=1.0 => neutral 0.5; faster actions score above neutral, slower actions below.
215	    const ratio = avgResponseMs / p75ResponseMs;
216	    const clamped = Math.max(0, Math.min(2, ratio));
217	    return Math.max(0, Math.min(1, 1 - clamped / 2));
218	}
