126	    canaryCache.set(customerId, model);
127	    canaryCacheLoadedAt.set(customerId, new Date());
128	    canaryLoadingPromise.delete(customerId);
129	    return model;
130	  })().catch((err) => {
131	    canaryCache.delete(customerId);
132	    canaryLoadingPromise.delete(customerId);
133	    console.error('[world-model] loadCanaryModel failed:', (err as Error).message);
